#include<bits/stdc++.h>using namespace std;int t,n,k,d,a[10010],b[100010],ans=0;int main(){	cin>>t;	while(t--){		cin>>n>>k>>d;		for(int i=1;i<=n;i++) cin>>a[i];		for(int i=1;i<=k;i++) cin>>b[i];		for(int i=0;i<=min(d-1,2*n);i++){			int x=(d-(i+1))/2;			for(int j=1;j<=i;j++){				for(int k=1;k<=b[j];k++) a[k]++;			}			for(int j=1;j<=n;j++){				if(a[j]==j) x++;			}			ans=max(ans,x);		}		cout<<ans<<endl;		ans=0;	}	return 0;}